var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제1 지구 사령 본부","JPN":"人類統合防衛軍第1地区指令本部","ENG":"United Humankind Defense Force, 1st District HQ","TWN":"人類共同保衛軍第一區司令總部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"……그렇게 해서, 5종 침식체에 도달한 아포리아는 제2 방위선을 돌파하고 있습니다.","JPN":"……そのようにして、第5種侵食体になったアポリアは第2防衛線を突破しようとしています。","ENG":"...Thus, Aporia has reached Category 5 and is currently breaching the 2nd Defense Line.","TWN":"……因此，進化成5類侵蝕體的阿波利亞正在突破第2防線。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"시뮬레이터의 예측 결과에 따르면……","JPN":"シミュレーターの予測結果によると……","ENG":"According to the predictions of the simulation...","TWN":"根據模擬器的預測結果……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"앞으로 48시간 뒤에 이곳, 제1 방위선에 도달할 예정입니다, 사령관님.","JPN":"これから48時間後、ここ第1防衛線に到達します、司令官。","ENG":"In 48 hours, it will reach the 1st Defense Line, Commander.","TWN":"再過48小時，將會抵達第一防線，司令官。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"알겠네, 나가보게.","JPN":"わかった、下がりたまえ。","ENG":"Understood. You may go now.","TWN":"知道了，出去吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"후우, 결국 여기까지 왔나.","JPN":"ふう、結局ここまで来たか。","ENG":"*Sigh* So it has come to this.","TWN":"呼，還是到這裡來了嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"가용할 수 있는 모든 화력도, 방위군의 병력도 이젠 한계에 다다랐어.","JPN":"使用できる火力も、防衛軍の兵力ももう限界だ。","ENG":"We have exhausted all of our firepower, and the Defense Force is at capacity.","TWN":"現在可使用的所有火力，保衛軍的兵力都達到了極限。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"사전에 예측하지 못했던 네피림 사태와 달리 이번에는 시간도 있었고, 작전도 써볼 만큼 써봤어.","JPN":"事前に予測できなかったネフィリムのときとは異なり、今回は時間的余裕もあったし、あらゆる作戦を試してもみた。","ENG":"Unlike the Nephil incident, which we could not predict, this time we had time and used all the tactics we could.","TWN":"與之前無法預測的諾菲力事件不同，這次我們有足夠的時間，也嘗試了各種作戰計畫。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"쓸 수 있는 모든 방법을 다 써도, 인류는 끝내 그 괴물을 쓰러트릴 수 없는 건가.","JPN":"あらゆる手を尽くしても、人類は結局あの化け物を倒すことができないのか。","ENG":"After employing all of our resources against it, there seems to be no way for mankind to stop this monster.","TWN":"用盡一切辦法，人類還是不能戰勝那個怪物嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GUARD_EXILER_CAP_A","text":{"KOREA":"사령관님, 지금이라도 늦지 않았습니다!","JPN":"司令官、まだ間に合います！","ENG":"Commander, it's still not too late!","TWN":"司令官，現在還來得及！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GUARD_EXILER_CAP_A","text":{"KOREA":"그 안토노프라는 작자가 말했던 이주 플랜에 동참해야만 합니다!","JPN":"あのアントノフという者が言っていた移住計画に加わるべきです！","ENG":"We must join that Antonov's emigration plan!","TWN":"我們必須參與那個叫安東諾夫的傢伙所說的移居計畫！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GUARD_EXILER_CAP_A","text":{"KOREA":"그들이 요구하는 물자를 제공해준다면, 적어도 저희 자리는 마련할 수 있을 겁니다!","JPN":"やつらの要求する物資を提供すれば、私たちの席くらいは用意してもらえるでしょう！","ENG":"If we provide the supplies they are asking for, they will arrange us with a place on the ship!","TWN":"如果向他們提供所需的物資，至少能有我們的位置！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GUARD_EXILER_CAP_B","text":{"KOREA":"맞습니다. 이제 우리 세계에 존재하는 함선은 그 엑자일러의 함선 한 대뿐입니다.","JPN":"そうです。もう我々の世界に存在する艦船は、あのエグザイラーの持つ一隻しかありません。","ENG":"He's right. The only remaining ship on this world is that Exile's.","TWN":"說的對，現在我們世界僅存的艦船，就只有那艘流浪者的艦船。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GUARD_EXILER_CAP_B","text":{"KOREA":"적어도 그 엑자일러의 의견을 들어볼 가치는 있다고 생각합니다.","JPN":"少なくともあのエグザイラーの話を聞いてみる価値はあるかと思います。","ENG":"I believe it will be at least worthwhile to hear the Exile's viewpoint.","TWN":"我認為至少可以聽聽那個流浪者的意見。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_QM","text":{"KOREA":"다들 아쉽게 됐군요.","JPN":"皆さん、残念でしたね。","ENG":"I'm afraid that will be difficult, everyone.","TWN":"很遺憾，各位。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_QM","text":{"KOREA":"왜냐하면, 그 엑자일러는 이제 존재하지 않으니까요.","JPN":"そのエグザイラーはもういません。","ENG":"Because the Exile doesn't exist anymore.","TWN":"那個流浪者現在已經不存在了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"소령?","JPN":"少佐？","ENG":"Major?","TWN":"少校？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"자네? 어쩌다가 눈을?","JPN":"君？　眼はどうした？","ENG":"Major, your eye...","TWN":"你？你的眼睛怎麼了？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"따라서 도망친다는 선택지는 존재하지 않습니다. 이제 저희는 싸울 수밖에 없어요.","JPN":"よって、逃げるという選択肢はありません。もう私たちは戦うしかないんです。","ENG":"So, the option of running away is no more. We have no choice but to fight.","TWN":"所以，逃跑已經行不通了。現在我們除了戰鬥，別無選擇。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사령관님, 저에게 제1 방위선의 모든 지휘권을 양도해주십시오.","JPN":"司令官、私に第1防衛線のすべての指揮権をお譲りください。","ENG":"Commander, let me take charge of the 1st Defense Line.","TWN":"司令官，請將第一防線的所有指揮權轉交給我。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"하지만 뭔가 대책이 있는 건가, 소령?","JPN":"それは構わないが、何か対策があるのか、少佐？","ENG":"Does that mean you have a plan, Major?","TWN":"你有什麼對策嗎，少校？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"그동안 우리가 가진 모든 수단을 다 사용했는데도 적을 막을 수 없었어.","JPN":"これまでどんな手を使っても、敵を止めることができなかったんだぞ。","ENG":"We've exhausted all options and still can't stop our enemies.","TWN":"這段時間我們用盡一切手段都無法阻擋敵人。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"이제 이곳 본부가 뚫리는 것도 시간 문제겠지…….","JPN":"この本部が突破されるのも時間の問題だろう……","ENG":"It will only be a matter of time before they breach HQ...","TWN":"現在總部被突破也只是時間問題……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"하루하루 다가오는 멸망 앞에서 대체 우리가 뭘 할 수 있단 말인가?","JPN":"日ごとに迫ってくる滅亡を前にして、これ以上我々にいったい何ができると言うんだ？","ENG":"What are we supposed to do when destruction is approaching closer every day?","TWN":"面對不斷逼近的滅亡，我們到底還能做什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"최종적으로는……","JPN":"最終的には……","ENG":"Ultimately...","TWN":"雖然最後……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리는 우리 세계가 막다른 길에 치닫는 걸 막을 수 없을지도 모르겠죠.","JPN":"私たちはこの世界が袋小路に突き進んでいくのを止められないのかもしれません。","ENG":"We may not be able to stop our world from hitting a dead end.","TWN":"我們無法保證我們的世界不會陷入絕境。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 적어도 지금은 그때가 아닙니다.","JPN":"しかし、少なくとも今はその時ではありません。","ENG":"But now is not the time for that, at least.","TWN":"但至少不是現在。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"자네 대체 무슨 말을?","JPN":"君、いったい何を言っている？","ENG":"What are you trying to say?","TWN":"這到底是什麼意思？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어떤 일이 있더라도, 저는 반드시 아포리아를 쓰러트릴 겁니다.","JPN":"何があっても、必ず私はアポリアを倒します。","ENG":"Whatever happens, I will defeat Aporia.","TWN":"不管發生什麼事，我一定要打倒阿波利亞。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리 세계는…… 그 뒤에 덤으로 구해드리죠.","JPN":"この世界は……そのあとについでに助けます。","ENG":"As a result of that... I will save our world.","TWN":"那之後……我一定會拯救我們的世界。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"역시 여기 계셨네요, 카린 양.","JPN":"やっぱりここに居たんですね、カリンさん。","ENG":"There you are, Karin.","TWN":"你果然在這裡，卡琳。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이걸 대령님께 돌려드리려고 했거든요.","JPN":"これを大佐にお返ししようと思って。","ENG":"I wanted to return this to Colonel.","TWN":"我本來想把這個還給上校的。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이건 <color=#ffd34c>선글라스</color>네요?","JPN":"これは<color=#ffd34c>サングラス</color>？","ENG":"<color=#ffd34c>Sunglasses</color>?","TWN":"這是……上校的<color=#ffd34c>墨鏡</color>？"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"크로스로드 작전 이후 대령님의 시신은 발견되지 않았지만, 유품을 정리한 게 저였거든요.","JPN":"クロスロード作戦の後、大佐の遺体は見つかりませんでしたが、遺品を片付けたのは私でした。","ENG":"Although his body was never found after Operation Crossroads, I was the one who organized his belongings.","TWN":"十字路口作戰之後，雖然沒有發現上校的遺體，但為他整理遺物的是我。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 뒤로 줄곧 제가 가지고 있었어요.","JPN":"それ以来、ずっと私が持っていたんです。","ENG":"I've been holding on to it all this time.","TWN":"那之後我就一直帶在身上。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"너무 늦은 것 같지만, 이제는 돌려드려야겠죠.","JPN":"遅すぎましたが、もうお返ししないと。","ENG":"It's a little too late, but I should return it to its rightful owner.","TWN":"雖然有些晚，但該還給他了。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"미안해요, 시영 씨.","JPN":"ごめんなさい、シノンさん。","ENG":"I'm sorry, Shiyoung.","TWN":"抱歉，時雨。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨 말이 맞았어요. 저는 결국 대령님처럼 영웅은 될 수 없었어요.","JPN":"シノンさんの言うとおりでした。結局私は大佐みたいな英雄にはなれませんでした。","ENG":"You were right. I couldn't become a hero like Colonel.","TWN":"你說的對。我終究還是無法成為像上校一樣的英雄。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"융통성 없고, 고집 세고, 어설프고, 걱정 많고, 눈물 많고, 잔소리도 심한 저지만.","JPN":"融通が利かなくて、意地っ張りで、不器用で、心配性で、涙もろくて、小言が多いですけど。","ENG":"I'm stubborn, strict, clumsy, worrisome, emotional, and nag all the time.","TWN":"雖然我不知變通、固執己見、輕率莽撞、愛瞎操心、愛哭，也很愛嘮叨。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"으, 으헤…… 그걸 다 기억하고 계셨어요?","JPN":"ア、ハハ……全部覚えてたんですか？","ENG":"W-whoa... You remember all of that?","TWN":"呃……你都記得喔？"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는 저예요.","JPN":"私は私です。","ENG":"I'm me.","TWN":"但我就是我。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는 혼자가 아닌 모두의 힘을 빌려, 앞으로 나아가겠어요.","JPN":"私はひとりではなく、皆の力を借りて前に進みます。","ENG":"I'm going to move forward with the help of everyone, not just myself.","TWN":"我會借用大家的力量，不再孤身一人向前。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그걸 자랑스럽게 생각하겠어요.","JPN":"それを誇らしく思うことにします。","ENG":"I'm going to think proudly of this.","TWN":"並且，我以此為榮。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까 시영 씨.","JPN":"ですから、シノンさん。","ENG":"So, Shiyoung.","TWN":"所以，時雨。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저와 함께 이 길을 걸어주시겠어요?","JPN":"私と共に来てくれませんか？","ENG":"Will you walk down this path with me?","TWN":"你願意和我一起踏上這條路嗎？"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"물론이에요. 그 말, 기다리고 있었다고요.","JPN":"もちろんです。その言葉を待ってたんです。","ENG":"Of course. I was waiting for you to say that.","TWN":"那當然，我就等你這句話。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자, 함께 살아남아 보자고요, 카린 양.","JPN":"それじゃ、一緒に生き残りましょうか、カリンさん。","ENG":"Okay, let's try to survive this together, Karin.","TWN":"讓我們一起活下去吧，卡琳。"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"마지막에 마지막까지 살아남아서 모두의 예상을 깨주자고요!","JPN":"最後の最後まで生き残って、みんなをあっと言わせましょう！","ENG":"We'll stay alive until the end and beat everyone's expectations!","TWN":"活到最後一刻，創造奇蹟！"},"stage":{"bg":"TOMB","bgm":"THEMA_CA_DELTA_KYLE_AP_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};